            {selectedElementIds.length > 1 ? (
              <div className="grid grid-cols-3 gap-1">
                <button onClick={() => alignSelected('left')} title={t('alignLeft')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M4 2v20M8 6h12M8 12h8M8 18h10"/></svg>
                </button>
                <button onClick={() => alignSelected('center')} title={t('alignCenter')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M12 2v20M6 6h12M8 12h8M6 18h12"/></svg>
                </button>
                <button onClick={() => alignSelected('right')} title={t('alignRight')} className="p-2 bg-gray-100 hover:bg-gray-200 rounded-md flex justify-center transition-colors">
                  <svg className="w-4 h-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M20 2v20M4 6h12M8 12h8M4 18h10"/></svg>
